// Example service definition - in a real project this would be generated from .proto files
// For demonstration, we define a simple Greeter service manually

// GreeterServer implements a simple greeting service
type GreeterServer struct {
	UnimplementedGreeterServer
}

// UnimplementedGreeterServer provides forward compatibility
type UnimplementedGreeterServer struct{}

// SayHello implements the SayHello RPC method
func (s *GreeterServer) SayHello(ctx context.Context, req *HelloRequest) (*HelloReply, error) {
	if req.Name == "" {
		return nil, status.Error(codes.InvalidArgument, "name cannot be empty")
	}
	return &HelloReply{
		Message: fmt.Sprintf("Hello, %s!", req.Name),
	}, nil
}

// SayGoodbye implements the SayGoodbye RPC method
func (s *GreeterServer) SayGoodbye(ctx context.Context, req *HelloRequest) (*HelloReply, error) {
	if req.Name == "" {
		return nil, status.Error(codes.InvalidArgument, "name cannot be empty")
	}
	return &HelloReply{
		Message: fmt.Sprintf("Goodbye, %s!", req.Name),
	}, nil
}

