func main() {
	port := 50051
	lis, err := net.Listen("tcp", fmt.Sprintf(":%d", port))
	if err != nil {
		log.Fatalf("Failed to listen on port %d: %v", port, err)
	}

	// Create gRPC server with common options for microservices
	grpcServer := grpc.NewServer(
		grpc.UnaryInterceptor(loggingInterceptor),
		grpc.MaxRecvMsgSize(4*1024*1024), // 4MB max message size
		grpc.MaxSendMsgSize(4*1024*1024),
	)

	// Register application services
	// In a real project with protobuf generated code, you would use:
	// pb.RegisterGreeterServer(grpcServer, &GreeterServer{})
	// pb.RegisterHealthServer(grpcServer, &HealthServer{})

	// Enable gRPC reflection in ALL environments (dev, staging, production)
	// This allows clients to discover services and methods dynamically using tools like:
	// - grpcurl: grpcurl -plaintext localhost:50051 list
	// - grpc_cli: grpc_cli ls localhost:50051
	// - Evans: evans --host localhost --port 50051
	// - Postman gRPC
	//
	// Reflection is intentionally kept enabled in production for:
	// 1. Easier debugging of production issues
	// 2. Dynamic service discovery in microservices architecture
	// 3. Integration testing against live services
	// 4. API exploration without needing .proto files
	reflection.Register(grpcServer)

	log.Printf("gRPC server starting on port %d", port)
	log.Printf("Reflection API enabled - services discoverable via grpcurl/grpc_cli")
	log.Printf("Registered services:")
	for name, info := range grpcServer.GetServiceInfo() {
		log.Printf("  Service: %s", name)
		for _, method := range info.Methods {
			log.Printf("    Method: %s", method.Name)
		}
	}
	log.Println("")
	log.Println("Try discovering services with:")
	log.Printf("  grpcurl -plaintext localhost:%d list", port)
	log.Printf("  grpcurl -plaintext localhost:%d describe", port)

	if err := grpcServer.Serve(lis); err != nil {
		log.Fatalf("Failed to serve gRPC server: %v", err)
	}
}

// loggingInterceptor logs all incoming gRPC requests
func loggingInterceptor(
	ctx context.Context,
	req interface{},
	info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler,
) (interface{}, error) {
	log.Printf("gRPC call: %s", info.FullMethod)
	resp, err := handler(ctx, req)
	if err != nil {
		log.Printf("gRPC call %s failed: %v", info.FullMethod, err)
	} else {
		log.Printf("gRPC call %s succeeded", info.FullMethod)
	}
	return resp, err
}